def load_last_id() -> int:
    if WATERMARK_FILE.exists():
        return json.loads(WATERMARK_FILE.read_text()).get("last_id", 0)
    return 0

def save_last_id(last_id: int) -> None:
    WATERMARK_FILE.write_text(json.dumps({"last_id": last_id}))

def extract_by_id(conn, table: str, id_column: str = "id") -> list[dict]:
    last_id = load_last_id()

    query = f"""
        SELECT * FROM {table}
        WHERE {id_column} > %(last_id)s
        ORDER BY {id_column} ASC
        LIMIT 10000
    """

    with conn.cursor() as cur:
        cur.execute(query, {"last_id": last_id})
        columns = [desc[0] for desc in cur.description]
        rows = [dict(zip(columns, row)) for row in cur.fetchall()]

    if rows:
        max_id = max(row[id_column] for row in rows)
        save_last_id(max_id)

    return rows

-- Create a changelog table
CREATE TABLE orders_changelog (
    id          BIGSERIAL PRIMARY KEY,
    operation   VARCHAR(10) NOT NULL,  -- INSERT, UPDATE, DELETE
    changed_at  TIMESTAMPTZ DEFAULT NOW(),
    old_data    JSONB,
    new_data    JSONB
);

-- Create the trigger function
CREATE OR REPLACE FUNCTION capture_order_changes()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO orders_changelog(operation, new_data)
        VALUES ('INSERT', row_to_json(NEW)::jsonb);
    ELSIF TG_OP = 'UPDATE' THEN
        INSERT INTO orders_changelog(operation, old_data, new_data)
        VALUES ('UPDATE', row_to_json(OLD)::jsonb, row_to_json(NEW)::jsonb);
    ELSIF TG_OP = 'DELETE' THEN
        INSERT INTO orders_changelog(operation, old_data)
        VALUES ('DELETE', row_to_json(OLD)::jsonb);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Attach the trigger
CREATE TRIGGER orders_cdc_trigger
AFTER INSERT OR UPDATE OR DELETE ON orders
FOR EACH ROW EXECUTE FUNCTION capture_order_changes();

import json
from pathlib import Path

class FileWatermarkStore:
    def __init__(self, path: str = "watermark.json"):
        self.path = Path(path)

    def get(self, key: str, default=None):
        if not self.path.exists():
            return default
        return json.loads(self.path.read_text()).get(key, default)

    def set(self, key: str, value) -> None:
        data = json.loads(self.path.read_text()) if self.path.exists() else {}
        data[key] = value
        self.path.write_text(json.dumps(data, default=str))

